import React, { useContext, useEffect, useState } from 'react';
import { AuthContext } from '../context/AuthContext';
import API from '../services/api';

const Profile = () => {
  const { user } = useContext(AuthContext);
  const [profile, setProfile] = useState(null);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const { data: profileData } = await API.get('/auth/profile');
        setProfile(profileData.user);
        const { data: ordersData } = await API.get('/orders/my-orders');
        setOrders(ordersData.orders);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to load profile');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) return <div className="container mt-4"><h2>Loading...</h2></div>;
  if (error) return <div className="container mt-4"><p className="text-danger">{error}</p></div>;

  return (
    <div className="container mt-4">
      <div className="profile-card p-4 shadow-sm bg-white rounded">
        <div className="d-flex align-items-center mb-4">
          <FaUserCircle className="profile-avatar me-3" size={64} />
          <div>
            <h2 className="mb-0">{profile?.name || profile?.email?.split('@')[0] || 'User'}'s Profile</h2>
            <p className="mb-0"><strong>Email:</strong> {profile?.email}</p>
            <p className="mb-0"><strong>Role:</strong> {profile?.role?.toLowerCase() === 'admin' ? 'Administrator' : (profile?.role?.charAt(0).toUpperCase() + profile?.role?.slice(1) || 'User')}</p>
          </div>
        </div>
        <button className="btn btn-outline-primary mb-4">Edit Profile</button>

        <h3 className="mt-4">Order History</h3>
        {orders.length === 0 ? (
          <p>No orders yet.</p>
        ) : (
          <ul className="list-group">
            {orders.map((order) => (
              <li key={order._id} className="list-group-item">
                <p><strong>Order ID:</strong> {order._id}</p>
                <p><strong>Total:</strong> ${order.total.toFixed(2)}</p>
                <p><strong>Status:</strong> {order.status}</p>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

export default Profile;
